class Solution:
    def numberOfWays(self, n: int, x: int) -> int:
        MOD = 10**9 + 7
        powers = []
        i = 1
        while True:
            val = i ** x
            if val > n:
                break
            powers.append(val)
            i += 1

        dp = [0] * (n + 1)
        dp[0] = 1
        for num in powers:
            for s in range(n, num - 1, -1):
                dp[s] = (dp[s] + dp[s - num]) % MOD

        return dp[n] % MOD

